import java.io.ByteArrayInputStream
import java.io.File
import java.io.FileInputStream
import java.net.URI

fun Context.getViewerAssetLoader(domain: String): WebViewAssetLoader {
    val mediaDir = CollectionHelper.getMediaDirectory(this)
    // WebViewAssetLoader matches on the URL's host (without port). Some callers pass a
    // host:port string (eg "127.0.0.1:12345"), so normalize here.
    val normalizedDomain = try {
        URI("http://$domain/").host ?: domain
    } catch (_: Exception) {
        domain.substringBefore(':')
    }

    return WebViewAssetLoader.Builder()
        .setHttpAllowed(true)
        .setDomain(normalizedDomain)
"}

